import{_ as a,o,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"194. Shift Work Allowances","description":"","frontmatter":{"title":"194. Shift Work Allowances","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/allowances/194-shift-work-allowances.md","filePath":"ebas/mental-health/management-admin/allowances/194-shift-work-allowances.md"}'),s={name:"ebas/mental-health/management-admin/allowances/194-shift-work-allowances.md"};function r(i,e,h,l,c,f){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_194-shift-work-allowances" tabindex="-1">194. Shift Work Allowances <a class="header-anchor" href="#_194-shift-work-allowances" aria-label="Permalink to &quot;194. Shift Work Allowances&quot;">​</a></h1><p><strong>194.1</strong> Definitions In this clause 194:</p><p><strong>(a)</strong> Morning shift means any shift that commences between 6:00 p.m. and 6:30 a.m.</p><p><strong>(b)</strong> Afternoon shift means any shift that finishes between 6:00 p.m. and 8:00 a.m.</p><p><strong>(c)</strong> Night shift means any shift that finishes on the day after commencing duty or commence after midnight and before 5:00 a.m.</p><p><strong>(d)</strong> Sunday night shift means a shift worked by a full-time or part-time Employee that commences on Sunday and concludes on Monday.</p><p><strong>(e)</strong> Permanent night shift Employee means an Employee permanently working on any such rostered hours of ordinary night duty for any period in excess of four consecutive weeks.</p><p><strong>194.2</strong> Application Where a shift meets more than one definition as set out in 194.1, the Employee be paid one shift allowance only, with the higher shift allowance where the rates differ.</p><p><strong>194.3</strong> Shift Allowances</p><p>In addition to any other rates prescribed elsewhere in this Agreement, the Employee will receive the following allowances where an Employee works:</p><p><strong>(a)</strong> A Morning Shift, an allowance set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty</p><p><strong>(b)</strong> An Afternoon Shift, an amount set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty</p><p><strong>(c)</strong> A Temporary Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as &#39;Weekday Night Duty&#39; for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday&#39;.</p><p><strong>(iii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as &#39;Sun Night Duty&#39; for each period of duty commencing on a Sunday.</p><p><strong>(d)</strong> A Permanent Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as &#39;Weekday Night Duty&#39; for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday.</p><p><strong>(iii)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non-casual Employee, the amount referred to in Schedule 2 as &#39;Sun Night Duty&#39; for each period of duty commencing on a Sunday.</p><p><strong>194.4</strong> Change of Shift Allowance</p><p><strong>(a)</strong> Provided further that in the case of an Employee who changes from working on one shift to working on another shift, the time of commencement of which differs by four hours or more than from that of the first, shall be paid the &#39;Change of Shift Allowance&#39; in Schedule 2on the occasion of each such change in addition to any amount payable under the preceding provisions of this clause.</p><p><strong>(b)</strong> Notwithstanding the provisions of clause 194.4(a) [215.4(a)] above, the change of shift allowance is not payable where the Employer agrees to a request in writing made on behalf of one or more Employees for changes in shifts.</p><p><strong>(c)</strong> Change of shift allowance is not payable where a single Employee holds two contemporaneous different contracted positions with the same Employer and moving between those positions results in a change of shift pattern which would ordinarily invoke a change of shift allowance payment.</p>',26)])])}const m=a(s,[["render",r]]);export{p as __pageData,m as default};
